-- N2 (화산) 덱 시드 데이터 - 자동 생성됨
-- 출처: 일단합격 JLPT 완벽대비 N2 단어장 PDF

delete from public.examples
  where word_id in (
    select w.id from public.words w
    join public.decks d on d.id = w.deck_id
    where d.is_official and d.jlpt_level = 'N2'
  );
delete from public.words
  where deck_id in (select id from public.decks where is_official and jlpt_level='N2');

do $$
declare
  d_n2 uuid;
  w uuid;
begin
  select id into d_n2 from public.decks where jlpt_level='N2' and is_official limit 1;

end $$;
